@app.route('/metrics')
def metrics():
    """Expose Prometheus metrics endpoint with optional authentication."""
    # If METRICS_AUTH_TOKEN is configured, require Bearer token authentication
    if METRICS_AUTH_TOKEN:
        auth_header = request.headers.get('Authorization', '')
